## Code Example

```javascript
class TokenBucket {
  constructor(rate, burst) {
    this.rate = rate; // tokens per second
    this.burst = burst; // max tokens
    this.tokens = burst;
    this.last = Date.now();
  }
  consume(n = 1) {
    this._refresh();
    if (this.tokens >= n) {
      this.tokens -= n;
      return true;
    }
    return false;
  }
  _refresh() {
    const now = Date.now();
    const elapsed = (now - this.last) / 1000;
    this.tokens = Math.min(this.burst, this.tokens + elapsed * this.rate);
    this.last = now;
  }
}
```

