- Postgres unique constraints + ON CONFLICT
- Kafka transactional producer with exactly-once semantics
- Multi-layer dedup enforcement (API → DB → Consumer)
- Request-id as idempotency key

## Code Example

```javascript
// API layer - generate and validate request-id
app.post('/events', async (req, res) => {
  const requestId = req.headers['x-request-id'] || uuidv4();

  const query = `
    INSERT INTO events (request_id, payload, created_at) 
    VALUES ($1, $2, NOW()) 
    ON CONFLICT (request_id) DO NOTHING
    RETURNING id
  `;

  const result = await client.query(query, [requestId, req.body]);
  if (!result.rows.length) {
    return res.status(409).json({ error: 'Duplicate request' });
  }

  // Transactional outbox
  await client.query(`
    INSERT INTO event_outbox (event_id, topic, payload, created_at)
    VALUES ($1, 'events', $2, NOW())
  `, [result.rows[0].id, req.body]);

  res.json({ requestId, eventId: result.rows[0].id });
});

// Outbox poller with transactional producer
const pollOutbox = async () => {
  const producer = kafka.producer({ transactionalId: 'event-producer' });
  await producer.connect();

  while (true) {
    const txn = await producer.transaction();
    try {
      const records = await client.query(`
        SELECT * FROM event_outbox 
        WHERE processed = false 
        ORDER BY created_at ASC 
        LIMIT 100
      `);

      for (const record of records.rows) {
        await txn.send({
          topic: record.topic,
          messages: [{ value: record.payload, key: record.event_id }]
        });

        await client.query(`
          UPDATE event_outbox 
          SET processed = true 
          WHERE id = $1
        `, [record.id]);
      }

      await txn.commit();
    } catch (error) {
      await txn.abort();
    }
    await sleep(100);
  }
};

// Consumer with idempotency cache
const consumer = kafka.consumer({ groupId: 'event-processors' });
const processedCache = new Redis();

await consumer.subscribe({ topic: 'events', fromBeginning: true });

await consumer.run({
  eachMessage: async ({ message }) => {
    const requestId = message.key.toString();
    const exists = await processedCache.exists(requestId);
    if (exists) return;

    await processEvent(message.value);
    await processedCache.setex(requestId, 3600, 'processed');
  }
});
```

