// Pseudo middleware: per-tenant quota enforcement
function quotaCheck(req, res, next) {
  const tenant = req.headers['x-tenant'];
  const limit = getTenantQuota(tenant);
  if ((inFlight[tenant] || 0) >= limit) return res.status(429).send('Too busy');
  inFlight[tenant] = (inFlight[tenant] || 0) + 1;
  res.on('finish', () => { inFlight[tenant]--; });
  next();
}
