async function isBetaEnabled(redis, cache, ttl = 1000) {
  let v = cache.get(FLAG_KEY);
  if (typeof v !== 'boolean') {
    v = await redis.get(FLAG_KEY);
    cache.set(FLAG_KEY, v, ttl);
  }
  return Boolean(v);
}
