// Attach lineage metadata at ingress
function tagEvent(event) {
  const eventId = crypto.randomUUID();
  event.headers = event.headers || {};
  event.headers['x-event-id'] = eventId;
  event.metadata = {
    eventId,
    ingressTimestamp: new Date().toISOString(),
    source: 'api-gateway'
  };
  return event;
}

// Propagate through Kafka headers
function sendToKafka(producer, topic, event) {
  const headers = {
    'x-event-id': event.metadata.eventId,
    'x-source': event.metadata.source
  };
  return producer.send({ topic, messages: [{ key: event.metadata.eventId, headers, value: event }] });
}

// Persist lineage to PostgreSQL
async function persistLineage(client, event, transforms, destination) {
  await client.query(
    `INSERT INTO event_lineage (event_id, source, destination, transforms, timestamp)
     VALUES ($1, $2, $3, $4, $5)`,
    [event.metadata.eventId, event.metadata.source, destination, JSON.stringify(transforms), new Date()]
  );
}
