// Per-tenant in-flight limiter
class InFlightLimiter {
  constructor(limit) {
    this.tenantCounts = new Map();
    this.globalCount = 0;
    this.limit = limit;
  }

  allow(tenant) {
    const current = this.tenantCounts.get(tenant) || 0;
    if (current >= this.tenantLimit || this.globalCount >= this.limit) {
      return false;
    }
    this.tenantCounts.set(tenant, current + 1);
    this.globalCount++;
    return true;
  }

  release(tenant) {
    const current = this.tenantCounts.get(tenant) || 0;
    this.tenantCounts.set(tenant, Math.max(0, current - 1));
    this.globalCount = Math.max(0, this.globalCount - 1);
  }
}
```

