async function upsertDedup(key, payload) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    // Upsert idempotency key
    await client.query(
      'INSERT INTO idempotency_keys (key, result) VALUES ($1, NULL) ON CONFLICT (key) DO NOTHING',
