- Sampling strategies to balance observability with performance overhead

## Code Example

```javascript
import { NodeTracerProvider } from '@opentelemetry/node';
import { registerInstrumentations } from '@opentelemetry/instrumentation';
import { HttpInstrumentation } from '@opentelemetry/instrumentation-http';
import { PgInstrumentation } from '@opentelemetry/instrumentation-pg';
import { RedisInstrumentation } from '@opentelemetry/instrumentation-redis-4';
import { KafkaInstrumentation } from '@opentelemetry/instrumentation-kafkajs';
import { BatchSpanProcessor } from '@opentelemetry/sdk-trace-base';
import { ParentBasedSampler, TraceIdRatioBasedSampler } from '@opentelemetry/sdk-trace-base';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';

const provider = new NodeTracerProvider({
  sampler: new ParentBasedSampler({
    root: new TraceIdRatioBasedSampler(0.15),
  }),
});

const otlpExporter = new OTLPTraceExporter();
provider.addSpanProcessor(new BatchSpanProcessor(otlpExporter));

registerInstrumentations({
  instrumentations: [
    new HttpInstrumentation(),
    new PgInstrumentation(),
    new RedisInstrumentation(),
    new KafkaInstrumentation(),
  ],
});

provider.register();
```

